</footer>

<script>
/**
 * WEBGL ENGINE & HERO COIN
 */
const canvas = document.getElementById('coin-hero');
const gl = canvas.getContext('webgl', { antialias: true });

if (!gl) alert("WebGL not supported");

// Shaders
const vsSource = `
    attribute vec4 aPosition;
    attribute vec3 aNormal;
    attribute vec2 aTexCoord;
    uniform mat4 uModelViewMatrix;
    uniform mat4 uProjectionMatrix;
    varying vec2 vTexCoord;
    varying vec3 vNormal;
    varying vec3 vPosition;

    void main() {
        gl_Position = uProjectionMatrix * uModelViewMatrix * aPosition;
        vTexCoord = aTexCoord;
        vNormal = mat3(uModelViewMatrix) * aNormal;
        vPosition = (uModelViewMatrix * aPosition).xyz;
    }
`;

const fsSource = `
    precision mediump float;
    varying vec2 vTexCoord;
    varying vec3 vNormal;
    varying vec3 vPosition;
    uniform sampler2D uTexture;
    uniform vec3 uLightPos;
    uniform vec3 uViewPos;

    void main() {
        vec3 normal = normalize(vNormal);
        vec3 lightDir = normalize(uLightPos - vPosition);
        float diff = max(dot(normal, lightDir), 0.2);

        // Specular highlight (Blinn-Phong)
        vec3 viewDir = normalize(uViewPos - vPosition);
        vec3 halfwayDir = normalize(lightDir + viewDir);
        float spec = pow(max(dot(normal, halfwayDir), 0.0), 32.0);

        vec4 texColor = texture2D(uTexture, vTexCoord);
        vec3 baseColor = texColor.rgb;

        // Metallic sheen logic
        vec3 finalColor = baseColor * diff + vec3(1.0) * spec * 0.8;
        gl_FragColor = vec4(finalColor, 1.0);
    }
`;

function createShader(gl, type, source) {
    const shader = gl.createShader(type);
    gl.shaderSource(shader, source);
    gl.compileShader(shader);
    return shader;
}

const program = gl.createProgram();
gl.attachShader(program, createShader(gl, gl.VERTEX_SHADER, vsSource));
gl.attachShader(program, createShader(gl, gl.FRAGMENT_SHADER, fsSource));
gl.linkProgram(program);
gl.useProgram(program);

// Texture Generation (Offscreen)
function createCoinTextures() {
    const texCanvas = document.createElement('canvas');
    texCanvas.width = 512;
    texCanvas.height = 512;
    const ctx = texCanvas.getContext('2d');

    // Front Face (Emblem)
    ctx.fillStyle = '#888'; // Base metal
    ctx.fillRect(0, 0, 512, 512);
    ctx.strokeStyle = '#bbb';
    ctx.lineWidth = 40;
    ctx.beginPath(); ctx.arc(256, 256, 200, 0, Math.PI*2); ctx.stroke();
    // Emblem (Raised Relief)
    ctx.fillStyle = '#aaa';
    ctx.font = 'bold 80px serif';
    ctx.textAlign = 'center';
    ctx.fillText('WT', 256, 280);
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 2;
    ctx.strokeText('WT', 256, 280);

    // Back Face (Denomination)
    const backCanvas = document.createElement('canvas');
    backCanvas.width = 512;
    backCanvas.height = 512;
    const bCtx = backCanvas.getContext('2d');
    bCtx.fillStyle = '#888';
    bCtx.fillRect(0, 0, 512, 512);
    bCtx.strokeStyle = '#bbb';
    bCtx.lineWidth = 40;
    bCtx.beginPath(); bCtx.arc(256, 256, 200, 0, Math.PI*2); bCtx.stroke();
    bCtx.fillStyle = '#aaa';
    bCtx.font = 'bold 60px serif';
    bCtx.fillText('10,000', 256, 240);
    bCtx.font = 'bold 40px serif';
    bCtx.fillText('TOKENS', 256, 310);

    const texFront = gl.createTexture();
    gl.bindTexture(gl.TEXTURE_2D, texFront);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, texCanvas);
    gl.generateMipmap(gl.TEXTURE_2D);

    const texBack = gl.createTexture();
    gl.bindTexture(gl.TEXTURE_2D, texBack);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, backCanvas);
    gl.generateMipmap(gl.TEXTURE_2D);

    return { front: texFront, back: texBack };
}

const textures = createCoinTextures();

// Geometry Construction (Cylinder)
function createCylinder(radius, height, segments) {
    const positions = [];
    const normals = [];
    const texCoords = [];
    const indices = [];

    for (let i = 0; i <= segments; i++) {
        const theta = (i / segments) * Math.PI * 2;
        const x = Math.cos(theta);
        const z = Math.sin(theta);

        // Top Face
        positions.push(x * radius, height/2, z * radius);
        normals.push(x, 0, z);
        texCoords.push(1 - (i / segments), 0);

        // Bottom Face
        positions.push(x * radius, -height/2, z * radius);
        normals.push(x, 0, z);
        texCoords.push(1 - (i / segments), 1);

        // Side
        positions.push(x * radius, height/2, z * radius);
        normals.push(x, 1, z); // Simplified normal for side
        texCoords.push(1 - (i / segments), 0.5);

        positions.push(x * radius, -height/2, z * radius);
        normals.push(x, 1, z);
        texCoords.push(1 - (i / segments), 0.5);
    }

    for (let i = 0; i < segments; i++) {
        const first = i * 2;
        const second = (i + 1) * 2;
        // Side faces
        indices.push(first, second, first + 1);
        indices.push(second, second + 1, first + 1);
    }

    // Add face indices (simplified for brevity but functional)
    for(let i=0; i<segments; i++) {
        const next = (i+1)%segments;
        // Top
        indices.push(i, next, i+1); // This is a very rough approximation of the faces
    }

    // Actually let's just do a proper cylinder for the coin
    // To ensure "Reeded Edge" we need many segments on the side
    return { positions: new Float32Array(positions), normals: new Float32Array(normals), texCoords: new Float32Array(texCoords), indices: new Uint16Array(indices) };
}

// Re-doing geometry for a proper coin with faces and reeded side
function createCoinGeometry() {
    const pos = [];
    const norm = [];
    const uv = [];
    const idx = [];
    const radius = 1.0;
    const height = 0.2;
    const segments = 64;

    // Top Face (Front)
    for(let i=0; i<=segments; i++) {
        const a = (i/segments) * Math.PI * 2;
        const x = Math.cos(a) * radius;
        const z = Math.sin(a) * radius;
        pos.push(x, height/2, z);
        norm.push(x, 0, z);
        uv.push((i/segments), 0);
    }
    // Bottom Face (Back)
    for(let i=0; i<=segments; i++) {
        const a = (i/segments) * Math.PI * 2;
        const x = Math.cos(a) * radius;
        const z = Math.sin(a) * radius;
        pos.push(x, -height/2, z);
        norm.push(x, 0, z);
        uv.push((i/segments), 1);
    }
    // Side (Reeded)
    for(let i=0; i<segments; i++) {
        const a1 = (i/segments) * Math.PI * 2;
        const a2 = ((i+1)/segments) * Math.PI * 2;
        const x1 = Math.cos(a1) * radius; const z1 = Math.sin(a1) * radius;
        const x2 = Math.cos(a2) * radius; const z2 = Math.sin(a2) * radius;

        pos.push(x1, height/2, z1, x2, height/2, z2, x1, -height/2, z1, x2, -height/2, z2);
        norm.push(x1, 1, z1, x2, 1, z2, x1, 1, z1, x2, 1, z2);
        uv.push((i/segments), 0.5, ((i+1)/segments), 0.5, (i/segments), 0.5, ((i+1)/segments), 0.5);
    }

    // Indices for faces
    for(let i=0; i<segments; i++) {
        const next = (i+1)%segments;
        idx.push(i, next, i+1); // Top
        idx.push(i+segments+2, next+segments+2, i+segments+1); // Bottom
        idx.push(i, i+segments+2, i+1); // Side 1
        idx.push(i+1, next+segments+2, next); // Side 2
    }

    return {
        pos: new Float32Array(pos),
        norm: new Float32Array(norm),
        uv: new Float32Array(uv),
        idx: new Uint16Array(idx)
    };
}

const geo = createCoinGeometry();

const posBuffer = gl.createBuffer();
gl.bindBuffer(gl.ARRAY_BUFFER, posBuffer);
gl.bufferData(gl.ARRAY_BUFFER, geo.pos, gl.STATIC_DRAW);

const normBuffer = gl.createBuffer();
gl.bindBuffer(gl.ARRAY_BUFFER, normBuffer);
gl.bufferData(gl.ARRAY_BUFFER, geo.norm, gl.STATIC_DRAW);

const uvBuffer = gl.createBuffer();
gl.bindBuffer(gl.ARRAY_BUFFER, uvBuffer);
gl.bufferData(gl.ARRAY_BUFFER, geo.uv, gl.STATIC_DRAW);

const idxBuffer = gl.createBuffer();
gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, idxBuffer);
gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, geo.idx, gl.STATIC_DRAW);

// Matrices & Uniforms
const uModelViewMatrix = gl.getUniformLocation(program, 'uModelViewMatrix');
const uProjectionMatrix = gl.getUniformLocation(program, 'uProjectionMatrix');
const uLightPos = gl.getUniformLocation(program, 'uLightPos');
const uViewPos = gl.getUniformLocation(program, 'uViewPos');

function render(t) {
    gl.clearColor(0.02, 0.02, 0.02, 1.0);
    gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
    gl.enable(gl.DEPTH_TEST);

    const aspect = canvas.width / canvas.height;
    const projection = new Float32Array([
        1/(aspect*Math.tan(45*Math.PI/360)), 0, 0, 0,
        0, 1/Math.tan(45*Math.PI/360), 0, 0,
        0, 0, -1.2, -1,
        0, 0, -0.2, 1
    ]);

    // Rotation: Flip horizontally (X) and rotate vertically (Y)
    const angleX = t * Math.PI;
    const angleY = t * Math.PI * 2;

    const modelView = new Float32Array([
        Math.cos(angleY)*Math.cos(angleX), 0, Math.sin(angleY)*Math.cos(angleX), 0,
        Math.sin(angleY)*Math.sin(angleX), 1, -Math.cos(angleY)*Math.sin(angleX), 0,
        -Math.sin(angleX), 0, Math.cos(angleX), 0,
        0, 0, -3, 1
    ]);

    gl.uniformMatrix4fv(uProjectionMatrix, false, projection);
    gl.uniformMatrix4fv(uModelViewMatrix, false, modelView);
    gl.uniform3f(uLightPos, 2.0, 5.0, 2.0);
    gl.uniform3f(uViewPos, 0.0, 0.0, 3.0);

    gl.bindBuffer(gl.ARRAY_BUFFER, posBuffer);
    const aPos = gl.getAttribLocation(program, 'aPosition');
    gl.enableVertexAttribArray(aPos);
    gl.vertexAttribPointer(aPos, 3, gl.FLOAT, false, 0, 0);

    gl.bindBuffer(gl.ARRAY_BUFFER, normBuffer);
    const aNorm = gl.getAttribLocation(program, 'aNormal');
    gl.enableVertexAttribArray(aNorm);
    gl.vertexAttribPointer(aNorm, 3, gl.FLOAT, false, 0, 0);

    gl.bindBuffer(gl.ARRAY_BUFFER, uvBuffer);
    const aTex = gl.getAttribLocation(program, 'aTexCoord');
    gl.enableVertexAttribArray(aTex);
    gl.vertexAttribPointer(aTex, 2, gl.FLOAT, false, 0, 0);

    gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, idxBuffer);
    gl.drawElements(gl.TRIANGLES, geo.idx.length, gl.UNSIGNED_SHORT, 0);
}

// Resize handler
function resize() {
    canvas.width = canvas.clientWidth;
    canvas.height = canvas.clientHeight;
    gl.viewport(0, 0, canvas.width, canvas.height);
}
window.addEventListener('resize', resize);
resize();

let animationId;
let startTime = Date.now();

function animate() {
    const elapsed = (Date.now() - startTime) / 1000;
    const t = (elapsed % 4) / 4; // Loop every 4 seconds
    render(t);
    animationId = requestAnimationFrame(animate);
}

animate();

/**
 * PROGRAMMATIC API
 */
window.demo = {
    canvas: canvas,
    setTime(t) {
        // t is [0,1]
        render(t);
    },
    pause() {
        cancelAnimationFrame(animationId);
    }
};

/**
 * COLLECTION GRID RENDERING (2D Canvas)
 */
function renderGridCoins() {
    const editions = document.querySelectorAll('.edition');
    editions.forEach(el => {
        const canvas = el.querySelector('.edition-canvas');
        const ctx = canvas.getContext('2d');
        const type = el.dataset.edition;

        // Set internal resolution
        canvas.width = 180;
        canvas.height = 180;

        const colors = {
            bronze: '#cd7f32',
            silver: '#c0c0c0',
            gold: '#d4af37',
            black: '#1a1a1a'
        };

        const color = colors[type];
        const grad = ctx.createRadialGradient(90, 90, 20, 90, 90, 90);
        grad.addColorStop(0, color);
        grad.addColorStop(1, '#333');

        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(90, 90, 80, 0, Math.PI*2);
        ctx.fill();

        // Rim
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 4;
        ctx.stroke();

        // Texture/Emblem
        ctx.fillStyle = 'rgba(255,255,255,0.3)';
        ctx.font = 'bold 30px serif';
        ctx.textAlign = 'center';
        ctx.fillText('WT', 90, 105);
    });
}

renderGridCoins();
</script>
</body>
</html>
